"use server";

import { prisma } from "@/lib/prisma";
import { vehicleSchema, VehicleFormValues } from "@/lib/validations";
import { revalidatePath } from "next/cache";

export async function getVehicles() {
  try {
    const vehicles = await prisma.vehicle.findMany({
      orderBy: { id: "desc" },
    });
    return { success: true, data: vehicles };
  } catch (error) {
    console.error("Failed to fetch vehicles:", error);
    return { success: false, error: "Failed to fetch vehicles" };
  }
}

export async function createVehicle(data: VehicleFormValues) {
  try {
    const validatedData = vehicleSchema.parse(data);
    
    // Check for unique registration
    const existing = await prisma.vehicle.findUnique({
      where: { registrationNo: validatedData.registrationNo },
    });
    
    if (existing) {
      return { success: false, error: "Registration number already exists" };
    }

    const vehicle = await prisma.vehicle.create({
      data: validatedData,
    });
    
    revalidatePath("/fleet");
    revalidatePath("/");
    
    return { success: true, data: vehicle };
  } catch (error) {
    console.error("Failed to create vehicle:", error);
    return { success: false, error: "Failed to create vehicle" };
  }
}

export async function deleteVehicle(id: number) {
  try {
    await prisma.vehicle.delete({
      where: { id },
    });
    revalidatePath("/fleet");
    revalidatePath("/");
    return { success: true };
  } catch (error) {
    return { success: false, error: "Failed to delete vehicle" };
  }
}
